import requests
from urllib.parse import urlparse

url = body.get('webhook_url')
parsed = urlparse(url)

# Deny internal IPs
BLOCKED = ['169.254.', '10.', '172.16.', '192.168.', '127.', '0.0.0.0']
if any(parsed.hostname.startswith(b) for b in BLOCKED):
    return {'statusCode': 400, 'body': 'Invalid URL'}

# Deny non-HTTPS
if parsed.scheme != 'https':
    return {'statusCode': 400, 'body': 'HTTPS required'}

response = requests.get(url, timeout=5)
